import {OptionButton, SubmitButton, QuizThemeContent} from "../components/Button"
import { useEffect } from 'react';

export default function Question(){
    useEffect(() => {
        fetch("assets/data.json").then((response) => {
            if(!response.ok) console.log("Bad data!")
            return response.json();
        }).then(data => {
            localStorage.setItem("quizzes", JSON.stringify(data));
        })
        console.log(JSON.parse(localStorage.getItem("quizzes")))
    })
    return (
        <main className="main">
            <div className="questionContainer">
                <div className="questionTextContainer">
                    <p className="questionNum">Question <span>6</span> of 10</p>
                    <h1 className='questionText'>Which of these color contrast ratios defines the minimum WCAG 2.1 Level AA requirement for normal text?</h1>
                </div>
                <div className="progressBarContainer">
                    <progress id="progress-bar" value="5" max="10"></progress>
                </div>
            </div>
            <div className="buttonGroup">
                <OptionButton>kek</OptionButton>
                <OptionButton>kek</OptionButton>
                <OptionButton>kek</OptionButton>
                <OptionButton>kek</OptionButton>
            </div>
        </main>
    )
}
